#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int PA, PB, PC;
        scanf("%d %d %d", &PA, &PB, &PC);
        int sum = PA + PC;
        int ans = (PB > sum) ? PB : sum;
        printf("%d\n", ans);
    }
    return 0;
}

